The reference solution of that problem in Typescript is 
function solve(nums: number[], k: number): number {
    nums.sort((a, b) => a - b);
    let maxLen = 0;
    for (let i = 0; i < nums.length; i++) {
        const target = nums[i] * k;
        let low = i;
        let high = nums.length - 1;
        let best = i - 1;
        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                best = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        const currentLen = best - i + 1;
        if (currentLen > maxLen) {
            maxLen = currentLen;
        }
    }
    return nums.length - maxLen;
}

